      margin-top: 8px;
      font-size: 14px;
      color: rgba(255, 255, 255, 0.5);
    }

    .input-section {
      margin-bottom: 28px;
    }

    label {
      display: block;
      font-size: 13px;
      font-weight: 600;
      color: rgba(255, 255, 255, 0.6);
      text-transform: uppercase;
      letter-spacing: 1px;
      margin-bottom: 10px;
    }

    .input-wrapper {
      position: relative;
    }

    input[type="text"] {
      width: 100%;
      padding: 16px 50px 16px 18px;
      background: rgba(255, 255, 255, 0.08);
      border: 2px solid rgba(255, 255, 255, 0.12);
      border-radius: 14px;
      font-size: 17px;
      color: #ffffff;
      outline: none;
