      line-height: 1;
      padding: 4px;
    }

    .clear-btn:hover {
      color: #e94560;
      transform: translateY(-50%) scale(1.2);
    }

    .divider {
      display: flex;
      align-items: center;
      gap: 14px;
      margin-bottom: 28px;
    }

    .divider-line {
      flex: 1;
      height: 1px;
      background: rgba(255, 255, 255, 0.1);
    }

    .divider-arrow {
      font-size: 22px;
      color: #e94560;
      animation: bounce 1.4s ease-in-out infinite;
    }

    @keyframes bounce {
      0%, 100% { transform: translateY(0); }
      50% { transform: translateY(5px); }
    }

    .output-section {
      margin-bottom: 28px;
    }

    .output-box {
      min-height: 68px;
      background: rgba(233, 69, 96, 0.07);
      border: 2px solid rgba(233, 69, 96, 0.2);
      border-radius: 14px;
      padding: 16px 18px;
      display: flex;
      align-items: center;
      flex-wrap: wrap;
      gap: 2px;
      transition: border-color 0.3s;
    }

    .output-box.has-content {
      border-color: rgba(233, 69, 96, 0.45);
    }

    .placeholder-text {
      color: rgba(255, 255, 255, 0.2);
      font-size: 17px;
      font-style: italic;
    }

    .char {
      display: inline-block;
      font-size: 17px;
      color: #ffffff;
      font-weight: 500;
      animation: pop-in 0.25s cubic-bezier(0.34, 1.56, 0.64, 1) both;
      white-space: pre;
    }

    @keyframes pop-in {
      0% {
        opacity: 0;
        transform: translateY(-10px) scale(0.5);
      }
      100% {
        opacity: 1;
        transform: translateY(0) scale(1);
      }
    }

    .char:nth-child(odd) {
      color: #f5a7b4;
    }

    .char:nth-child(even) {
      color: #a7c5f5;
    }

    .stats-row {
      display: flex;
      gap: 12px;
      margin-bottom: 28px;
    }

    .stat-card {
      flex: 1;
      background: rgba(255, 255, 255, 0.05);
      border: 1px solid rgba(255, 255, 255, 0.08);
      border-radius: 12px;
      padding: 14px 16px;
      text-align: center;
      transition: background 0.3s;
    }

    .stat-card:hover {
      background: rgba(255, 255, 255, 0.09);
    }

    .stat-value {
      font-size: 26px;
      font-weight: 700;
      color: #e94560;
      display: block;
      line-height: 1;
      margin-bottom: 5px;
    }

    .stat-label {
      font-size: 11px;
      color: rgba(255, 255, 255, 0.4);
      text-transform: uppercase;
      letter-spacing: 0.8px;
    }

    .copy-btn {
      width: 100%;
      padding: 15px;
      background: linear-gradient(135deg, #e94560, #c23152);
