<body>

  <div class="container">
    <div class="header">
      <span class="icon">🔄</span>
      <h1>String Reverser</h1>
      <p>Type anything and watch it flip in real time</p>
    </div>

    <div class="input-section">
      <label for="inputText">Your Text</label>
      <div class="input-wrapper">
        <input
          type="text"
          id="inputText"
          placeholder="Start typing here..."
          autocomplete="off"
          spellcheck="false"
        />
        <button class="clear-btn" id="clearBtn" title="Clear input">✕</button>
      </div>
    </div>

    <div class="divider">
      <div class="divider-line"></div>
      <span class="divider-arrow">↓</span>
      <div class="divider-line"></div>
    </div>

    <div class="output-section">
      <label>Reversed Output</label>
      <div class="output-box" id="outputBox">
        <span class="placeholder-text" id="placeholderText">Reversed text will appear here…</span>
      </div>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <span class="stat-value" id="charCount">0</span>
        <span class="stat-label">Characters</span>
      </div>
      <div class="stat-card">
        <span class="stat-value" id="wordCount">0</span>
        <span class="stat-label">Words</span>
      </div>
      <div class="stat-card">
        <span class="stat-value" id="spaceCount">0</span>
        <span class="stat-label">Spaces</span>
      </div>
    </div>

    <button class="copy-btn" id="copyBtn" disabled>Copy Reversed Text</button>
  </div>

  <div class="toast" id="toast">✅ Copied to clipboard!</div>

  <script>
    const inputText   = document.getElementById('inputText');
    const outputBox   = document.getElementById('outputBox');
    const placeholder = document.getElementById('placeholderText');
    const clearBtn    = document.getElementById('clearBtn');
    const copyBtn     = document.getElementById('copyBtn');
    const charCount   = document.getElementById('charCount');
    const wordCount   = document.getElementById('wordCount');
    const spaceCount  = document.getElementById('spaceCount');
    const toast       = document.getElementById('toast');

    let animationTimer = null;

    function reverseString(str) {
      return str.split('').reverse().join('');
    }

    function updateStats(str) {
      charCount.textContent = str.length;
      wordCount.textContent = str.trim() === '' ? 0 : str.trim().split(/\s+/).length;
      spaceCount.textContent = (str.match(/ /g) || []).length;
    }

    function renderReversed(reversed) {
      // Clear previous content except placeholder
      const existingChars = outputBox.querySelectorAll('.char');
      existingChars.forEach(c => c.remove());

      if (reversed.length === 0) {
        placeholder.style.display = 'block';
        outputBox.classList.remove('has-content');
        copyBtn.disabled = true;
        return;
      }

      placeholder.style.display = 'none';
      outputBox.classList.add('has-content');
      copyBtn.disabled = false;

      // Animate characters appearing one by one with staggered delay
      reversed.split('').forEach((char, index) => {
        const span = document.createElement('span');
        span.classList.add('char');
        span.textContent = char;
        span.style.animationDelay = `${index * 30}ms`;
        outputBox.appendChild(span);
      });
    }

    function handleInput() {
      const val = inputText.value;

      // Show/hide clear button
      clearBtn.style.display = val.length > 0 ? 'block' : 'none';

      // Update stats
      updateStats(val);

      // Debounce the animation slightly for fast typing
      if (animationTimer) clearTimeout(animationTimer);
      animationTimer = setTimeout(() => {
        renderReversed(reverseString(val));
      }, 60);
    }

    clearBtn.addEventListener('click', () => {
      inputText.value = '';
      inputText.focus();
      handleInput();
    });

    copyBtn.addEventListener('click', () => {
      const reversed = reverseString(inputText.value);
      if (!reversed) return;

      navigator.clipboard.writeText(reversed).then(() => {
        copyBtn.textContent = '✓ Copied!';
        copyBtn.classList.add('copied');

        toast.classList.add('show');

        setTimeout(() => {
          copyBtn.textContent = 'Copy Reversed Text';
          copyBtn.classList.remove('copied');
          toast.classList.remove('show');
        }, 2000);
      }).catch(() => {
        // Fallback for older browsers
        const ta = document.createElement('textarea');
        ta.value = reversed;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);

        copyBtn.textContent = '✓ Copied!';
        copyBtn.classList.add('copied');
        toast.classList.add('show');

        setTimeout(() => {
          copyBtn.textContent = 'Copy Reversed Text';
          copyBtn.classList.remove('copied');
          toast.classList.remove('show');
        }, 2000);
      });
    });

    inputText.addEventListener('input', handleInput);

    // Auto-focus on load
    inputText.focus();
  </script>
</body>
</html>
