        <button class="clear-btn" id="clearBtn" title="Clear">✕</button>
      </div>
      <div class="char-count"><span id="charCount">0</span> characters</div>
    </div>

    <div class="arrow-section">
      <div class="arrow-line"></div>
      <div class="arrow-icon">↕</div>
      <div class="arrow-line right"></div>
    </div>

    <div class="output-section">
      <label>Reversed Output</label>
      <div class="output-box" id="outputBox">
        <div class="shimmer"></div>
        <span class="placeholder-text">Your reversed text will appear here…</span>
      </div>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value" id="statChars">0</div>
        <div class="stat-label">Characters</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" id="statWords">0</div>
        <div class="stat-label">Words</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" id="statUnique">0</div>
        <div class="stat-label">Unique Chars</div>
      </div>
    </div>

    <button class="copy-btn" id="copyBtn" disabled>
      <span id="copyIcon">📋</span>
      <span id="copyLabel">Copy Reversed Text</span>
    </button>
  </div>

  <script>
    const inputEl   = document.getElementById('inputText');
    const outputBox = document.getElementById('outputBox');
    const clearBtn  = document.getElementById('clearBtn');
    const copyBtn   = document.getElementById('copyBtn');
    const copyIcon  = document.getElementById('copyIcon');
    const copyLabel = document.getElementById('copyLabel');
    const charCount = document.getElementById('charCount');
    const statChars = document.getElementById('statChars');
    const statWords = document.getElementById('statWords');
    const statUnique= document.getElementById('statUnique');

    let previousReversed = '';
    let copyTimeout = null;

    function reverseString(str) {
      return str.split('').reverse().join('');
    }

    function countWords(str) {
      const trimmed = str.trim();
      if (!trimmed) return 0;
      return trimmed.split(/\s+/).length;
    }

    function countUnique(str) {
      if (!str) return 0;
      return new Set(str.replace(/\s/g, '')).size;
    }

    function animateOutput(newReversed) {
      outputBox.innerHTML = '';

      if (!newReversed) {
        outputBox.classList.remove('has-content');
        const shimmer = document.createElement('div');
        shimmer.className = 'shimmer';
        outputBox.appendChild(shimmer);
        const ph = document.createElement('span');
        ph.className = 'placeholder-text';
        ph.textContent = 'Your reversed text will appear here…';
        outputBox.appendChild(ph);
        previousReversed = '';
        return;
      }

      outputBox.classList.add('has-content');

      const shimmer = document.createElement('div');
      shimmer.className = 'shimmer';
      outputBox.appendChild(shimmer);

      // Stagger each character animation
      [...newReversed].forEach((char, i) => {
        const span = document.createElement('span');
        span.className = 'char-span' + (char === ' ' ? ' space-char' : '');
        span.textContent = char === ' ' ? '\u00A0' : char;

        // Only animate chars that changed position or are new
        const wasTheSame = previousReversed[i] === char;
        if (!wasTheSame) {
          span.style.animationDelay = `${i * 18}ms`;
        } else {
          span.style.animation = 'none';
          span.style.opacity = '1';
        }

        outputBox.appendChild(span);
      });

      previousReversed = newReversed;
    }

    function updateStats(input) {
      const len   = input.length;
      const words = countWords(input);
      const uniq  = countUnique(input);

      charCount.textContent = len;
      statChars.textContent = len;
      statWords.textContent = words;
      statUnique.textContent = uniq;
    }

    function handleInput() {
      const value   = inputEl.value;
      const reversed = reverseString(value);

      clearBtn.style.display = value.length ? 'flex' : 'none';
      copyBtn.disabled = !value.length;

      animateOutput(reversed);
      updateStats(value);
    }

    clearBtn.addEventListener('click', () => {
      inputEl.value = '';
      inputEl.focus();
      handleInput();
    });

    copyBtn.addEventListener('click', async () => {
      const reversed = reverseString(inputEl.value);
      if (!reversed) return;

      try {
        await navigator.clipboard.writeText(reversed);
      } catch {
        // Fallback
        const ta = document.createElement('textarea');
        ta.value = reversed;
        ta.style.position = 'fixed';
        ta.style.opacity = '0';
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
      }

      copyBtn.classList.add('copied');
      copyIcon.textContent = '✅';
      copyLabel.textContent = 'Copied!';

      clearTimeout(copyTimeout);
      copyTimeout = setTimeout(() => {
        copyBtn.classList.remove('copied');
        copyIcon.textContent = '📋';
        copyLabel.textContent = 'Copy Reversed Text';
      }, 2000);
    });

    inputEl.addEventListener('input', handleInput);

    // Focus input on load
    inputEl.focus();
  </script>
</body>
</html>
