      />
    </div>

    <div class="divider">
      <div class="divider-line"></div>
      <span class="divider-icon">🔄</span>
      <div class="divider-line"></div>
    </div>

    <div class="output-section">
      <label>🪞 &nbsp;Reversed Output</label>
      <div class="output-box" id="outputBox">
        <span class="placeholder-text">...reversed text appears here</span>
      </div>
    </div>

    <div class="stats-row">
      <div class="stat-pill" id="charPill">
        <span>Chars</span>
        <span class="stat-value" id="charCount">0</span>
      </div>
      <div class="stat-pill" id="wordPill">
        <span>Words</span>
        <span class="stat-value" id="wordCount">0</span>
      </div>
      <div class="stat-pill" id="spacePill">
        <span>Spaces</span>
        <span class="stat-value" id="spaceCount">0</span>
      </div>
    </div>

    <button class="copy-btn" id="copyBtn" disabled>Copy Reversed Text</button>
    <button class="clear-btn" id="clearBtn" disabled>✕ &nbsp;Clear</button>

  </div>

  <script>
    const inputEl   = document.getElementById('inputText');
    const outputBox = document.getElementById('outputBox');
    const charCount = document.getElementById('charCount');
    const wordCount = document.getElementById('wordCount');
    const spaceCount= document.getElementById('spaceCount');
    const copyBtn   = document.getElementById('copyBtn');
    const clearBtn  = document.getElementById('clearBtn');
    const charPill  = document.getElementById('charPill');
    const wordPill  = document.getElementById('wordPill');
    const spacePill = document.getElementById('spacePill');

    let animTimeout = null;

    function reverseString(str) {
      return str.split('').reverse().join('');
    }

    function updateStats(str) {
      const chars  = str.length;
      const words  = str.trim() === '' ? 0 : str.trim().split(/\s+/).length;
      const spaces = (str.match(/ /g) || []).length;

      charCount.textContent  = chars;
      wordCount.textContent  = words;
      spaceCount.textContent = spaces;

      charPill.classList.toggle('active',  chars  > 0);
      wordPill.classList.toggle('active',  words  > 0);
      spacePill.classList.toggle('active', spaces > 0);
    }

    function renderOutput(reversed) {
      outputBox.innerHTML = '';

      if (reversed.length === 0) {
        outputBox.classList.remove('has-content');
        const ph = document.createElement('span');
        ph.className = 'placeholder-text';
        ph.textContent = '...reversed text appears here';
        outputBox.appendChild(ph);
        return;
      }

      outputBox.classList.add('has-content');

      reversed.split('').forEach((ch, i) => {
        const span = document.createElement('span');
        span.className = ch === ' ' ? 'char space' : 'char';
        span.textContent = ch === ' ' ? '\u00A0' : ch;
        span.style.animationDelay = `${i * 18}ms`;
        outputBox.appendChild(span);
      });
    }

    function handleInput() {
      const raw      = inputEl.value;
      const reversed = reverseString(raw);

      if (animTimeout) clearTimeout(animTimeout);

      renderOutput(reversed);
      updateStats(raw);

      const hasText = raw.length > 0;
      copyBtn.disabled  = !hasText;
      clearBtn.disabled = !hasText;
    }

    copyBtn.addEventListener('click', () => {
      const reversed = reverseString(inputEl.value);
      if (!reversed) return;

      navigator.clipboard.writeText(reversed).then(() => {
        copyBtn.textContent = '✓  Copied!';
        copyBtn.classList.add('copied');
        setTimeout(() => {
          copyBtn.textContent = 'Copy Reversed Text';
          copyBtn.classList.remove('copied');
        }, 2000);
      }).catch(() => {
        /* fallback for older browsers */
        const ta = document.createElement('textarea');
        ta.value = reversed;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        document.body.removeChild(ta);
        copyBtn.textContent = '✓  Copied!';
        copyBtn.classList.add('copied');
        setTimeout(() => {
          copyBtn.textContent = 'Copy Reversed Text';
          copyBtn.classList.remove('copied');
        }, 2000);
      });
    });

    clearBtn.addEventListener('click', () => {
      inputEl.value = '';
      handleInput();
      inputEl.focus();
    });

    inputEl.addEventListener('input', handleInput);

    /* init */
    handleInput();
  </script>
</body>
</html>
