    </div>

    <div class="output-section">
      <div class="output-label">
        Reversed Output
        <span class="live-badge">LIVE</span>
      </div>
      <div class="output-box" id="outputBox">
        <span class="placeholder-text">Your reversed text will appear here...</span>
      </div>
    </div>

    <div class="stats-row">
      <div class="stat-card">
        <div class="stat-value" id="statChars">0</div>
        <div class="stat-label">Characters</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" id="statWords">0</div>
        <div class="stat-label">Words</div>
      </div>
      <div class="stat-card">
        <div class="stat-value" id="statPalindrome">—</div>
        <div class="stat-label">Palindrome</div>
      </div>
    </div>

    <button class="copy-btn" id="copyBtn" disabled>
      <span id="copyIcon">📋</span>
      <span id="copyText">Copy Reversed Text</span>
