          span.classList.add('char-span', 'space-char');
          span.innerHTML = '&nbsp;';
        } else {
          span.classList.add('char-span', `color-${colorIndex % COLORS}`);
          span.textContent = char;
          colorIndex++;
        }

        outputBox.appendChild(span);
      });

      colorOffset = (colorOffset + 1) % COLORS;
    }

