      const chars  = text.length;
      const words  = countWords(text);
      const spaces = (text.match(/ /g) || []).length;

      statChars.textContent  = chars;
      statWords.textContent  = words;
      statSpaces.textContent = spaces;
      charCount.textContent  = `${chars} / 200`;
