<body>

<div class="card">
  <h1>String Reverser</h1>
  <p class="subtitle">Type below and watch your text flip in real time</p>

  <label for="inputText">Input</label>
  <textarea id="inputText" placeholder="Start typing anything…" spellcheck="false"></textarea>

  <div class="divider">
    <span class="divider-icon">⇅</span>
  </div>

  <label>Reversed Output</label>
  <div class="output-box empty" id="outputBox" aria-live="polite"></div>

  <div class="stats">
    <div class="stat">
      <div class="stat-value" id="charCount">0</div>
      <div class="stat-label">Characters</div>
    </div>
    <div class="stat">
      <div class="stat-value" id="wordCount">0</div>
      <div class="stat-label">Words</div>
    </div>
    <div class="stat">
      <div class="stat-value" id="lineCount">0</div>
      <div class="stat-label">Lines</div>
    </div>
  </div>

  <button class="copy-btn" id="copyBtn" disabled>Copy Reversed Text</button>
</div>

<script>
  const inputEl   = document.getElementById('inputText');
  const outputBox = document.getElementById('outputBox');
  const copyBtn   = document.getElementById('copyBtn');
  const charCount = document.getElementById('charCount');
  const wordCount = document.getElementById('wordCount');
  const lineCount = document.getElementById('lineCount');

  let animationTimer = null;
  let previousReversed = '';

  function reverseString(str) {
    return str.split('').reverse().join('');
  }

  function updateStats(text) {
    charCount.textContent = text.length;
    wordCount.textContent = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
    lineCount.textContent = text === '' ? 0 : text.split('\n').length;
  }

  function animateOutput(reversed) {
    if (animationTimer) {
      clearTimeout(animationTimer);
      animationTimer = null;
    }

    if (reversed === '') {
      outputBox.innerHTML = '';
      outputBox.classList.add('empty');
      copyBtn.disabled = true;
      previousReversed = '';
      return;
    }

    outputBox.classList.remove('empty');
    copyBtn.disabled = false;

    const prevLen = previousReversed.length;
    const newLen  = reversed.length;

    // Find how many leading characters are shared
    let shared = 0;
    while (
      shared < prevLen &&
      shared < newLen &&
      previousReversed[shared] === reversed[shared]
    ) {
      shared++;
    }

    // Rebuild only changed portion
    // Keep existing spans for shared prefix
    const existingSpans = outputBox.querySelectorAll('.char');

    // Remove spans beyond shared length
    for (let i = existingSpans.length - 1; i >= shared; i--) {
      existingSpans[i].remove();
    }

    // Append new characters with staggered animation
    const fragment = document.createDocumentFragment();
    for (let i = shared; i < newLen; i++) {
      const ch = reversed[i];
      const span = document.createElement('span');
      span.className = 'char highlight';
      span.textContent = ch === ' ' ? '\u00A0' : ch;
      span.style.animationDelay = `${(i - shared) * 22}ms`;
      fragment.appendChild(span);
    }
    outputBox.appendChild(fragment);

    previousReversed = reversed;
  }

  inputEl.addEventListener('input', () => {
    const text     = inputEl.value;
    const reversed = reverseString(text);
    updateStats(text);
    animateOutput(reversed);
  });

  copyBtn.addEventListener('click', () => {
    const text = previousReversed.replace(/\u00A0/g, ' ');
    if (!text) return;

    navigator.clipboard.writeText(text).then(() => {
      copyBtn.textContent = '✓ Copied!';
      copyBtn.classList.add('copied');
      setTimeout(() => {
        copyBtn.textContent = 'Copy Reversed Text';
        copyBtn.classList.remove('copied');
      }, 1800);
    }).catch(() => {
      // Fallback
      const ta = document.createElement('textarea');
      ta.value = text;
      ta.style.position = 'fixed';
      ta.style.opacity = '0';
      document.body.appendChild(ta);
      ta.select();
      document.execCommand('copy');
      document.body.removeChild(ta);
      copyBtn.textContent = '✓ Copied!';
      copyBtn.classList.add('copied');
      setTimeout(() => {
        copyBtn.textContent = 'Copy Reversed Text';
        copyBtn.classList.remove('copied');
      }, 1800);
    });
  });
</script>

</body>
</html>
