<body>

<div class="card">
  <h1 class="title">String Reverser</h1>
  <p class="subtitle">Type below and watch your text reverse in real time</p>

  <label for="inputText">Input</label>
  <textarea
    id="inputText"
    placeholder="Start typing here..."
    spellcheck="false"
    autocomplete="off"
  ></textarea>

  <div class="divider">
    <div class="divider-line"></div>
    <div class="divider-icon">⇅</div>
    <div class="divider-line"></div>
  </div>

  <label>Reversed Output</label>
  <div class="output-box empty-hint" id="outputBox">
    Reversed text will appear here...
  </div>

  <div class="stats">
    <div class="stat">
      <span class="stat-value" id="charCount">0</span>
      <span class="stat-label">Characters</span>
    </div>
    <div class="stat">
      <span class="stat-value" id="wordCount">0</span>
      <span class="stat-label">Words</span>
    </div>
    <div class="stat">
      <span class="stat-value" id="lineCount">0</span>
      <span class="stat-label">Lines</span>
    </div>
  </div>

  <button class="clear-btn" id="clearBtn">Clear</button>
</div>

<script>
  const inputText  = document.getElementById('inputText');
  const outputBox  = document.getElementById('outputBox');
  const charCount  = document.getElementById('charCount');
  const wordCount  = document.getElementById('wordCount');
  const lineCount  = document.getElementById('lineCount');
  const clearBtn   = document.getElementById('clearBtn');

  let animationTimer = null;
  let lastReversed = '';

  function reverseString(str) {
    return str.split('').reverse().join('');
  }

  function countWords(str) {
    const trimmed = str.trim();
    if (!trimmed) return 0;
    return trimmed.split(/\s+/).length;
  }

  function countLines(str) {
    if (!str) return 0;
    return str.split('\n').length;
  }

  function animateOutput(reversed) {
    if (animationTimer) {
      clearTimeout(animationTimer);
      animationTimer = null;
    }

    if (reversed === '') {
      outputBox.innerHTML = 'Reversed text will appear here...';
      outputBox.classList.add('empty-hint');
      outputBox.classList.remove('has-content');
      return;
    }

    outputBox.classList.remove('empty-hint');
    outputBox.classList.add('has-content');

    const chars = reversed.split('');
    outputBox.innerHTML = '';

    chars.forEach((ch, i) => {
      const span = document.createElement('span');
      span.classList.add('char');

      if (ch === '\n') {
        span.appendChild(document.createElement('br'));
      } else {
        span.textContent = ch;
      }

      span.style.animationDelay = `${i * 18}ms`;
      outputBox.appendChild(span);
    });
  }

  function updateStats(text) {
    charCount.textContent = text.length;
    wordCount.textContent = countWords(text);
    lineCount.textContent = countLines(text) || 0;
  }

  inputText.addEventListener('input', () => {
    const text = inputText.value;
    const reversed = reverseString(text);

    updateStats(text);

    if (reversed !== lastReversed) {
      lastReversed = reversed;
      animateOutput(reversed);
    }
  });

  clearBtn.addEventListener('click', () => {
    inputText.value = '';
    lastReversed = '';
    animateOutput('');
    updateStats('');
    inputText.focus();
  });
</script>

</body>
</html>
