<body>

  <div class="container">
    <div class="header">
      <h1>String Reverser</h1>
      <p>Type anything — watch it flip in real time</p>
    </div>

    <div class="card">

      <!-- Input -->
      <div>
        <div class="field-label"><span class="dot"></span> Input</div>
        <div class="input-wrap">
          <input
            id="inputField"
            type="text"
            placeholder="Start typing here…"
            autocomplete="off"
            spellcheck="false"
            maxlength="200"
          />
          <span class="char-counter" id="charCounter">0/200</span>
        </div>
      </div>

      <!-- Stats -->
      <div class="stats">
        <div class="stat-pill">✦ Chars <span class="val" id="statChars">0</span></div>
        <div class="stat-pill">⎵ Words <span class="val" id="statWords">0</span></div>
        <div class="stat-pill">🔄 Unique <span class="val" id="statUnique">0</span></div>
        <div class="stat-pill">⚡ Palindrome? <span class="val" id="statPalin">—</span></div>
      </div>

      <!-- Progress -->
      <div class="progress-bar-wrap">
        <div class="progress-bar" id="progressBar"></div>
      </div>

      <!-- Divider -->
      <div class="divider">
        <div class="arrow-icon">↕</div>
        reversed
      </div>

      <!-- Output -->
      <div>
        <div class="field-label"><span class="dot green"></span> Output</div>
        <div class="output-box" id="outputBox">
          <span class="empty-hint">Your reversed text will appear here…</span>
        </div>
      </div>

      <!-- Controls -->
      <div class="controls">
        <button id="copyBtn">⎘ Copy Result</button>
        <button id="swapBtn">⇄ Swap</button>
        <button id="clearBtn">✕ Clear</button>
      </div>

    </div>
  </div>

  <div class="toast" id="toast"></div>

  <script>
    const input       = document.getElementById('inputField');
    const outputBox   = document.getElementById('outputBox');
    const charCounter = document.getElementById('charCounter');
    const progressBar = document.getElementById('progressBar');
    const statChars   = document.getElementById('statChars');
    const statWords   = document.getElementById('statWords');
    const statUnique  = document.getElementById('statUnique');
    const statPalin   = document.getElementById('statPalin');
    const copyBtn     = document.getElementById('copyBtn');
    const clearBtn    = document.getElementById('clearBtn');
    const swapBtn     = document.getElementById('swapBtn');
    const toast       = document.getElementById('toast');

    // Hue palette cycling
    const palette = [
      '#ff6ab0','#ff9f6a','#ffe06a','#6affa3',
      '#6affda','#6ac4ff','#a56aff','#ff6aec'
    ];

    let toastTimer = null;

    function showToast(msg) {
      toast.textContent = msg;
      toast.classList.add('show');
      clearTimeout(toastTimer);
      toastTimer = setTimeout(() => toast.classList.remove('show'), 2000);
    }

    function isPalindrome(str) {
      const s = str.toLowerCase().replace(/[^a-z0-9]/g, '');
      if (!s) return null;
      return s === s.split('').reverse().join('');
    }

    function updateStats(val) {
      const len   = val.length;
      const words = val.trim() === '' ? 0 : val.trim().split(/\s+/).length;
      const unique = new Set(val.replace(/\s/g, '').toLowerCase()).size;
      const palin  = isPalindrome(val);

      statChars.textContent  = len;
      statWords.textContent  = words;
      statUnique.textContent = unique || 0;
      statPalin.textContent  = palin === null ? '—' : palin ? '✓ Yes' : '✗ No';
      statPalin.style.color  = palin ? 'var(--accent3)' : palin === false ? 'var(--accent2)' : '';

      charCounter.textContent = `${len}/200`;
      charCounter.style.color = len > 180 ? 'var(--accent2)' : 'var(--muted)';
      progressBar.style.width = `${(len / 200) * 100}%`;
    }

    function renderOutput(val) {
      const reversed = val.split('').reverse().join('');

      // Ripple effect
      const ripple = document.createElement('div');
      ripple.className = 'ripple';
      outputBox.appendChild(ripple);
      ripple.addEventListener('animationend', () => ripple.remove());

      if (!reversed) {
        outputBox.innerHTML = '<span class="empty-hint">Your reversed text will appear here…</span>';
        outputBox.classList.remove('active');
        return;
      }

      outputBox.classList.add('active');

      // Build chars with staggered animation delays
      const fragment = document.createDocumentFragment();
      [...reversed].forEach((ch, i) => {
        const span = document.createElement('span');
        span.className = 'char-span' + (ch === ' ' ? ' space-char' : '');
        span.textContent = ch === ' ' ? '\u00A0' : ch;

        // Assign color from palette based on position
        const color = palette[i % palette.length];
        span.style.setProperty('--char-color', color);

        // Stagger animation
        span.style.animationDelay = `${Math.min(i * 18, 300)}ms`;

        fragment.appendChild(span);
      });

      outputBox.innerHTML = '';
      outputBox.appendChild(ripple.cloneNode());
      outputBox.appendChild(fragment);
    }

    // Main handler
    input.addEventListener('input', () => {
      const val = input.value;
      updateStats(val);
      renderOutput(val);
    });

    // Copy
    copyBtn.addEventListener('click', () => {
      const reversed = input.value.split('').reverse().join('');
      if (!reversed) { showToast('Nothing to copy!'); return; }
      navigator.clipboard.writeText(reversed).then(() => {
        showToast('✓ Copied to clipboard!');
        copyBtn.textContent = '✓ Copied!';
        setTimeout(() => { copyBtn.innerHTML = '⎘ Copy Result'; }, 1500);
      }).catch(() => showToast('Copy failed'));
    });

    // Clear
    clearBtn.addEventListener('click', () => {
      input.value = '';
      input.dispatchEvent(new Event('input'));
      input.focus();
    });

    // Swap — put reversed into input
    swapBtn.addEventListener('click', () => {
      const reversed = input.value.split('').reverse().join('');
      if (!reversed) return;
      input.value = reversed;
      input.dispatchEvent(new Event('input'));
      showToast('⇄ Swapped!');
      input.focus();
    });

    // Focus input on load
    input.focus();
  </script>
</body>
</html>
```

