<script>
  const inputEl      = document.getElementById('inputText');
  const outputBox    = document.getElementById('outputBox');
  const charCount    = document.getElementById('charCount');
  const statChars    = document.getElementById('statChars');
  const statWords    = document.getElementById('statWords');
  const statSpaces   = document.getElementById('statSpaces');
  const statUniq     = document.getElementById('statUniq');
  const palindromeEl = document.getElementById('palindromeBanner');
  const progressFill = document.getElementById('progressFill');

  let prevReversed = '';
  let animFrame;

  function animateStat(el, newVal) {
    const cur = parseInt(el.textContent) || 0;
    if (cur === newVal) return;
    el.textContent = newVal;
    el.classList.remove('pop');
    void el.offsetWidth;
    el.classList.add('pop');
  }

  function buildOutput(text) {
    if (!text) {
      outputBox.innerHTML = '<span class="placeholder-text">Your reversed text will appear here…</span>';
      outputBox.classList.remove('has-content', 'sweep');
      return;
    }

    const reversed = text.split('').reverse().join('');
    const changed  = reversed !== prevReversed;
    prevReversed   = reversed;

    // Sweep animation on change
    if (changed) {
      outputBox.classList.remove('sweep');
      void outputBox.offsetWidth;
      outputBox.classList.add('sweep');
    }

    outputBox.classList.add('has-content');

    // Build char spans with staggered delays
    const fragment = document.createDocumentFragment();
    const maxDelay = Math.min(reversed.length * 18, 300);

    for (let i = 0; i < reversed.length; i++) {
      const ch = reversed[i];
      const span = document.createElement('span');
      span.className = 'char-span' + (ch === ' ' ? ' space' : '');
      span.textContent = ch;
      const delay = changed ? Math.min(i * 18, maxDelay) : 0;
      span.style.animationDelay = delay + 'ms';
      fragment.appendChild(span);
    }

    outputBox.innerHTML = '';
    outputBox.appendChild(fragment);
  }

  function updateStats(text) {
    const chars  = text.length;
    const words  = text.trim() ? text.trim().split(/\s+/).length : 0;
    const spaces = (text.match(/ /g) || []).length;
    const uniq   = new Set(text.replace(/\s/g,'')).size;

    animateStat(statChars,  chars);
    animateStat(statWords,  words);
    animateStat(statSpaces, spaces);
    animateStat(statUniq,   uniq);

    // Char count display
    charCount.textContent = chars + ' / 500';
    charCount.classList.toggle('active', chars > 0);

    // Progress bar
    progressFill.style.width = (chars / 500 * 100) + '%';

    // Palindrome check (ignore case, ignore spaces, min 2 chars)
    const clean = text.toLowerCase().replace(/\s/g, '');
    const isPalin = clean.length >= 2 && clean === clean.split('').reverse().join('');
    palindromeEl.classList.toggle('show', isPalin);
  }

  inputEl.addEventListener('input', () => {
    cancelAnimationFrame(animFrame);
    animFrame = requestAnimationFrame(() => {
      const val = inputEl.value;
      updateStats(val);
      buildOutput(val);
    });
  });

  function copyText() {
    const text = prevReversed;
    if (!text) return;
    navigator.clipboard.writeText(text).then(() => {
      const btn = document.getElementById('copyBtn');
      btn.classList.add('copied');
      btn.innerHTML = `<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="20 6 9 17 4 12"/></svg> Copied!`;
      setTimeout(() => {
        btn.classList.remove('copied');
        btn.innerHTML = `<svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg> Copy`;
      }, 2000);
    });
  }
</script>
</body>
</html>
