      </div>
    </div>
  </div>

  <script>
    const input = document.getElementById('inputField');
    const outputBox = document.getElementById('outputBox');
    const charCount = document.getElementById('charCount');
    const wordCount = document.getElementById('wordCount');
    const reverseTime = document.getElementById('reverseTime');

    input.addEventListener('input', () => {
      const start = performance.now();
      const text = input.value;
      const reversed = text.split('').reverse().join('');

      outputBox.innerHTML = '';

      if (reversed.length === 0) {
        outputBox.innerHTML = '<span class="placeholder-text">Your reversed text will appear here...</span>';
      } else {
        reversed.split('').forEach((char, i) => {
          const span = document.createElement('span');
          span.classList.add('char-span');
          if (char === ' ') {
            span.classList.add('space');
            span.textContent = '\u00A0';
          } else {
            span.textContent = char;
          }
          span.style.animationDelay = `${i * 18}ms`;
          outputBox.appendChild(span);
        });
      }

      // Update stats
      charCount.textContent = text.length;
      wordCount.textContent = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;

      const end = performance.now();
      reverseTime.textContent = `${(end - start).toFixed(1)}ms`;
    });
  </script>
</body>
</html>
```

### What it does:
- **Real-time reversal** — updates on every keystroke instantly
- **Character animation** — each character pops in with a staggered `popIn` animation
- **Live stats** — character count, word count, and render time
- **Modern glassmorphism UI** — gradient background, blurred card, glowing focus states
- **Fully self-contained** — single HTML file, zero dependencies

