  <script>
    const inputField = document.getElementById('inputField');
    const outputBox  = document.getElementById('outputBox');
    const charCount  = document.getElementById('charCount');
    const wordCount  = document.getElementById('wordCount');
    const clearBtn   = document.getElementById('clearBtn');

    function animateOutput(text) {
      outputBox.innerHTML = '';

      if (!text) {
        outputBox.classList.remove('active');
        outputBox.innerHTML = '<span class="placeholder-text">Your reversed text will appear here...</span>';
        return;
      }

      outputBox.classList.add('active');

      const reversed = text.split('').reverse().join('');

      // Cap animation delay for long strings
      const maxAnimated = 20;

      reversed.split('').forEach((ch, i) => {
        const span = document.createElement('span');
        span.classList.add('char');
        if (ch === ' ') span.classList.add('space');
        span.textContent = ch === ' ' ? '\u00A0' : ch;

        // For characters beyond 20, show instantly
        if (i >= maxAnimated) {
          span.style.opacity = '1';
          span.style.transform = 'none';
          span.style.animation = 'none';
        }

        outputBox.appendChild(span);
      });
    }

    function updateStats(text) {
      const chars = text.length;
      const words = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;

      charCount.textContent = `${chars} character${chars !== 1 ? 's' : ''}`;
      wordCount.textContent  = `${words} word${words !== 1 ? 's' : ''}`;

      charCount.classList.toggle('highlight', chars > 0);
      wordCount.classList.toggle('highlight', words > 0);
    }

    inputField.addEventListener('input', () => {
      const val = inputField.value;
      animateOutput(val);
      updateStats(val);
    });

    clearBtn.addEventListener('click', () => {
      inputField.value = '';
      animateOutput('');
      updateStats('');
      inputField.focus();
    });
  </script>
